export default function RoleplayTab({ topic, apiKey }) {
  return (
    <div className="aria-placeholder">
      <div className="aria-placeholder-icon">🎯</div>
      <p className="aria-placeholder-title">Roleplay Quests</p>
      <p className="aria-placeholder-sub">Topic: <strong>{topic}</strong></p>
      <p className="aria-placeholder-note">Coming in Step 5 — quest catalog &amp; NPC</p>
    </div>
  );
}
